import logging
import azure.functions as func
import os
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.identity import DefaultAzureCredential

def main(inputBlob: func.InputStream):
    # Process the file
    data = inputBlob.read()
    
    # Write results to Cosmos DB
    credential = DefaultAzureCredential()
    cosmos_client = CosmosClient(os.environ["COSMOS_ENDPOINT"], credential)
    database = cosmos_client.get_database_client(os.environ["COSMOS_DATABASE"])
    container = database.get_container_client(os.environ["COSMOS_CONTAINER"])
    container.upsert_item(data)
    
    # Send notifications via Event Grid
    event_grid_client = EventGridPublisherClient(os.environ["EVENT_GRID_ENDPOINT"], credential)
    event_grid_client.send_events([{
        "subject": "FileProcessed",
        "data": {
            "message": "File processed successfully"
        },
        "event_type": "Notification"
    }])